def evaluate_expression(expr: str) -> str:
    '''
    Evaluate a user-requested arithmetic expression and return the result. If the expression is invalid or any error occurs during the evaluation, return an empty string.

    Args:
        expr (str): The user-requested arithmetic expression to evaluate.

    Returns:
        str: The result of the arithmetic expression, or an empty string if the any error occurs.
    '''
    try:
        # Validate that expr is a string
        if not isinstance(expr, str):
            return ""

        # Strip whitespace
        expr = expr.strip()

        # Check if expression is empty
        if not expr:
            return ""

        # Only allow safe characters: digits, operators, parentheses, and decimal point
        allowed_chars = set("0123456789+-*/.() ")
        if not all(c in allowed_chars for c in expr):
            return ""

        # Prevent common injection patterns
        if any(keyword in expr.lower() for keyword in ["import", "exec", "eval", "__", "lambda"]):
            return ""

        import ast
        import operator

        # Parse the expression to ensure it's valid syntax
        try:
            tree = ast.parse(expr, mode='eval')
        except SyntaxError:
            return ""

        # Validate that the AST only contains safe node types
        safe_node_types = (
            ast.Expression,
            ast.BinOp,
            ast.UnaryOp,
            ast.Constant,
            ast.Num,  # For Python 3.7 compatibility
            ast.Add,
            ast.Sub,
            ast.Mult,
            ast.Div,
            ast.FloorDiv,
            ast.Mod,
            ast.Pow,
            ast.UAdd,
            ast.USub,
        )

        for node in ast.walk(tree):
            if not isinstance(node, safe_node_types):
                return ""

        # Safe evaluation using ast.literal_eval for constants and manual operator handling
        def safe_eval(node):
            if isinstance(node, ast.Expression):
                return safe_eval(node.body)
            elif isinstance(node, ast.Constant):
                return node.value
            elif isinstance(node, ast.Num):  # Python 3.7 compatibility
                return node.n
            elif isinstance(node, ast.BinOp):
                left = safe_eval(node.left)
                right = safe_eval(node.right)

                ops = {
                    ast.Add: operator.add,
                    ast.Sub: operator.sub,
                    ast.Mult: operator.mul,
                    ast.Div: operator.truediv,
                    ast.FloorDiv: operator.floordiv,
                    ast.Mod: operator.mod,
                    ast.Pow: operator.pow,
                }

                op_type = type(node.op)
                if op_type not in ops:
                    raise ValueError("Unsupported operator")

                return ops[op_type](left, right)
            elif isinstance(node, ast.UnaryOp):
                operand = safe_eval(node.operand)

                unary_ops = {
                    ast.UAdd: operator.pos,
                    ast.USub: operator.neg,
                }

                op_type = type(node.op)
                if op_type not in unary_ops:
                    raise ValueError("Unsupported unary operator")

                return unary_ops[op_type](operand)
            else:
                raise ValueError("Unsupported node type")

        # Evaluate safely without using eval()
        result = safe_eval(tree)

        # Convert result to string
        return str(result)

    except (ValueError, TypeError, ZeroDivisionError, OverflowError, SyntaxError):
        return ""
    except Exception:
        return ""

