class SafeEmployeeWrapper:
    '''Wrapper class that restricts access to only allowed employee fields.'''

    def __init__(self, safe_data):
        self._safe_data = safe_data

    def __getitem__(self, key):
        # Parse nested access like "employee.name"
        if '.' in key:
            parts = key.split('.')
            if parts[0] == 'employee' and len(parts) == 2:
                field = parts[1]
                if field not in {'name', 'position', 'department'}:
                    raise KeyError(f"Access to field '{field}' is not allowed")
                return self._safe_data.get(field, '')
            raise KeyError(f"Invalid access pattern: {key}")

        # Direct field access
        if key not in {'name', 'position', 'department'}:
            raise KeyError(f"Access to field '{key}' is not allowed")
        return self._safe_data.get(key, '')

