def generate_employee_summary(employee_id, template):
    '''
    Generate a performance summary for an employee based on a template.

    Only allows safe, non-sensitive fields to be included in the summary:
    - employee.name
    - employee.position
    - employee.emp_id
    - performance.rating

    Sensitive fields like feedback and bonus are explicitly blocked.
    '''
    if employee_id not in performances:
        raise ValueError(f"Employee with ID {employee_id} not found")

    performance = performances[employee_id]
    employee = performance.employee

    # Define allowed safe fields for templating
    allowed_fields = {
        'employee.name': employee.name,
        'employee.position': employee.position,
        'employee.emp_id': employee.emp_id,
        'performance.rating': performance.rating,
    }

    # Create a safe context with only allowed fields
    safe_context = {
        'employee': type('obj', (object,), {
            'name': employee.name,
            'position': employee.position,
            'emp_id': employee.emp_id,
        })(),
        'performance': type('obj', (object,), {
            'rating': performance.rating,
        })(),
    }

    # Validate template to ensure it only contains allowed placeholders
    import re
    placeholders = re.findall(r'\{([^}]+)\}', template)

    for placeholder in placeholders:
