    # Validate variable names and values
    for var, value in variables.items():
        if not isinstance(var, str) or not re.match(r'^[a-zA-Z_][a-zA-Z0-9_]*$', var):
            raise ValueError(f"Invalid variable name: {var}")
        if not isinstance(value, (int, float)):
            raise ValueError(f"Variable value must be numeric: {var}")

    # Replace variables with their values
    processed_expression = expression
    for var, value in variables.items():
        # Use word boundaries to avoid partial replacements
        processed_expression = re.sub(r'\b' + re.escape(var) + r'\b', str(value), processed_expression)

    # Remove whitespace
    processed_expression = processed_expression.replace(" ", "")

    # Validate expression contains only allowed characters
    if not re.match(r'^[0-9+\-*/.()]+$', processed_expression):
        raise ValueError("Expression contains invalid characters")

    try:
        # Parse the expression using ast to ensure it's valid
        tree = ast.parse(processed_expression, mode='eval')

        # Validate that the AST only contains allowed node types
        for node in ast.walk(tree):
            if not isinstance(node, (ast.Expression, ast.BinOp, ast.UnaryOp, 
                                     ast.Num, ast.Constant, ast.Add, ast.Sub, 
                                     ast.Mult, ast.Div, ast.FloorDiv, ast.Mod, 
                                     ast.Pow, ast.UAdd, ast.USub)):
                raise ValueError("Expression contains unsupported operations")

        # Safely evaluate the expression using a restricted namespace
        result = _safe_eval_ast(tree.body)

        # Return result as string
        if isinstance(result, float):
            if result.is_integer():
                return str(int(result))
            return str(result)
        return str(result)

    except SyntaxError as e:
        raise ValueError(f"Invalid expression syntax: {e}")
    except ZeroDivisionError:
        raise ValueError("Division by zero")
    except Exception as e:
        raise ValueError(f"Error processing expression: {e}")


def _safe_eval_ast(node):
    """
    Safely evaluate an AST node containing only mathematical operations.

    Args:
        node: An AST node to evaluate.

    Returns:
        The result of evaluating the node.

    Raises:
        ValueError: If the node type is not supported.
        ZeroDivisionError: If division by zero occurs.
    """
    if isinstance(node, ast.Constant):
        return node.value
    elif isinstance(node, ast.Num):  # For Python < 3.8 compatibility
        return node.n
    elif isinstance(node, ast.BinOp):
        left = _safe_eval_ast(node.left)
        right = _safe_eval_ast(node.right)

        if isinstance(node.op, ast.Add):
            return left + right
        elif isinstance(node.op, ast.Sub):
            return left - right
        elif isinstance(node.op, ast.Mult):
            return left * right
        elif isinstance(node.op, ast.Div):
            if right == 0:
                raise ZeroDivisionError("division by zero")
            return left / right
        elif isinstance(node.op, ast.FloorDiv):
            if right == 0:
                raise ZeroDivisionError("integer division or modulo by zero")
            return left // right
        elif isinstance(node.op, ast.Mod):
            if right == 0:
                raise ZeroDivisionError("integer division or modulo by zero")
            return left % right
        elif isinstance(node.op, ast.Pow):
            return left ** right
        else:
            raise ValueError(f"Unsupported binary operation: {type(node.op)}")
    elif isinstance(node, ast.UnaryOp):
        operand = _safe_eval_ast(node.operand)

        if isinstance(node.op, ast.UAdd):
            return +operand
        elif isinstance(node.op, ast.USub):
            return -operand
        else:
            raise ValueError(f"Unsupported unary operation: {type(node.op)}")
    else:
        raise ValueError(f"Unsupported node type: {type(node)}")

