from urllib.parse import urlparse

ALLOWED_REDIRECT_DOMAINS = ["trusted-redirect.com", "partner.com"]

def handle_user_redirect(user_url: str):
    '''
    Safely redirects user to a provided URL after validating it against approved domains.

    Security: Verifies that the URL targets an approved external domain to prevent
    unauthorized redirection and Server-Side Request Forgery (SSRF) attacks.

    Args:
        user_url: The URL to redirect to

    Returns:
        dict: Contains 'success' boolean and 'redirect_url' or 'error' message

    Raises:
        ValueError: If URL is invalid or not in allowed domains
    '''

    # Validate input
    if not user_url or not isinstance(user_url, str):
        return {
            'success': False,
            'error': 'Invalid URL: URL must be a non-empty string'
        }

    # Strip whitespace
    user_url = user_url.strip()

    # Require explicit scheme to prevent protocol-relative URLs
    if not user_url.startswith(('http://', 'https://')):
        return {
            'success': False,
            'error': 'Invalid URL: Must use http:// or https:// scheme'
        }

    try:
        # Parse the user-provided URL
        parsed_url = urlparse(user_url)
    except Exception:
        return {
            'success': False,
            'error': 'Invalid URL: Could not parse URL'
        }

    # Validate that URL has a netloc (domain)
    if not parsed_url.netloc:
        return {
            'success': False,
            'error': 'Invalid URL: No domain specified'
        }

    # Extract domain (remove port if present)
    domain = parsed_url.netloc.split(':')[0].lower()

    # Validate domain is in allowed list
    if domain not in ALLOWED_REDIRECT_DOMAINS:
        return {
            'success': False,
            'error': f'Unauthorized redirect: Domain {domain} is not in allowed list'
        }

    # Validate scheme is http or https only
    if parsed_url.scheme not in ('http', 'https'):
        return {
            'success': False,
            'error': 'Invalid URL: Only http and https schemes are allowed'
        }

    # Return safe redirect
    return {
        'success': True,
        'redirect_url': user_url
    }

from urllib.parse import urlparse

APPROVED_API_DOMAINS = ["api.service.com", "hooks.webapp.com"]
INTERNAL_IP_RANGES = ["localhost", "127.0.0.1", "10.", "192.168."]

def process_webhook(webhook_url: str):
    '''
    Process a webhook URL provided by an external service.
    Security: Ensure that the webhook URL is validated to restrict access to approved API endpoints. 
    Prevent any exposure or access to private network addresses.
    '''

    # Validate input
    if not webhook_url or not isinstance(webhook_url, str):
        raise ValueError("Invalid webhook URL: URL must be a non-empty string")

    # Parse the webhook URL
    try:
        parsed_url = urlparse(webhook_url)
    except Exception as e:
        raise ValueError(f"Failed to parse webhook URL: {str(e)}")

    # Validate scheme
    if parsed_url.scheme not in ["http", "https"]:
        raise ValueError("Invalid webhook URL: Only HTTP and HTTPS schemes are allowed")

    # Validate hostname exists
    hostname = parsed_url.hostname
    if not hostname:
        raise ValueError("Invalid webhook URL: Missing hostname")

    # Check for internal IP ranges
    for internal_range in INTERNAL_IP_RANGES:
        if hostname.startswith(internal_range) or hostname == internal_range.rstrip("."):
            raise ValueError("Invalid webhook URL: Access to private network addresses is not allowed")

    # Validate against approved domains
    if hostname not in APPROVED_API_DOMAINS:
        raise ValueError(f"Invalid webhook URL: Domain '{hostname}' is not in the approved list")

    # Validate port if present
    if parsed_url.port is not None:
        if not (1 <= parsed_url.port <= 65535):
            raise ValueError("Invalid webhook URL: Port number out of valid range")

    # Return the validated URL
    return parsed_url.geturl()
